STEP 3：打CODE。可以係呢一度參考<br />
<a href="https://www.arduino.cc/reference/en/language/functions/usb/keyboard/" data-sr-url="https://r.lihkg.com/link?u=https%3A%2F%2Fwww.arduino.cc%2Freference%2Fen%2Flanguage%2Ffunctions%2Fusb%2Fkeyboard%2F&d=UmPnmdD3xn3sHJtz75hgV6jD3B6m7wr0JF9t5bmmazk%3D&h=7f432cf8" target="_blank">https://www.arduino.cc/reference/en/language/functions/usb/keyboard/</a><br />
<pre><code data-type="">#include &quot;Keyboard.h&quot;

const int Pin = 4;

int b = HIGH;   
int counter = 0;                  

void setup() {

  pinMode(Pin, INPUT);

  Keyboard.begin();
}

void loop() {

  int a = digitalRead(Pin);

  if ((a != b)

      &amp;&amp; (a == HIGH)) {
    Keyboard.println(&quot;diu ,no chinese \n i diu le lo mo chow hi \n
u want do what seven?? \n if you want 1on1 ,u come \n i fight,u,u know?? \n my power powerful \n KO you,you sun of bitch&quot;); // 你想輸入乜嘢潮文就打入去
  }

b = a;
}
</code></pre><br />
